// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
// Define the structure for a tree edge
typedef struct Edge {
    int v, u, c;
} Edge;
// Define the structure for a tree node
typedef struct Node {
    int numEdges;
    Edge* edges;
} Node;
// Function to perform DFS
int dfs(Node* nodes, int currentNode, int parent, int* maxLen) {
    int len = 0;
    for (int i = 0; i < nodes[currentNode].numEdges; i++) {
        Edge edge = nodes[currentNode].edges[i];
        if (edge.u != parent) {
            int childLen = dfs(nodes, edge.u, currentNode, maxLen);
            // Check if the path from the current node to the child node and back is a palindrome
            if (childLen > 0 && edge.c == nodes[currentNode].edges[nodes[currentNode].numEdges - 1 - i].c) {
                len = childLen + 1;
            }
        }
    }
    if (len > *maxLen) {
        *maxLen = len;
    }
    return len;
}
// Main function
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        Node nodes[N];
        for (int i = 0; i < N - 1; i++) {
            int v, u, c;
            scanf("%d %d %d", &v, &u, &c);
            // Add the edge to the adjacency list
            nodes[v - 1].edges = realloc(nodes[v - 1].edges, (nodes[v - 1].numEdges + 1) * sizeof(Edge));
            nodes[v - 1].edges[nodes[v - 1].numEdges].v = v - 1;
            nodes[v - 1].edges[nodes[v - 1].numEdges].u = u - 1;
            nodes[v - 1].edges[nodes[v - 1].numEdges].c = c;
            nodes[v - 1].numEdges++;
            nodes[u - 1].edges = realloc(nodes[u - 1].edges, (nodes[u - 1].numEdges + 1) * sizeof(Edge));
            nodes[u - 1].edges[nodes[u - 1].numEdges].v = u - 1;
            nodes[u - 1].edges[nodes[u - 1].numEdges].u = v - 1;
            nodes[u - 1].edges[nodes[u - 1].numEdges].c = c;
            nodes[u - 1].numEdges++;
        }
        int maxLen = 0;
        for (int i = 0; i < N; i++) {
            dfs(nodes, i, -1, &maxLen);
        }
        printf("%d\n", maxLen);
    }
    return 0;
}

