import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;
public class Main {
    // Define the structure for a tree edge
    static class Edge {
        int v, u, c;
        public Edge(int v, int u, int c) {
            this.v = v;
            this.u = u;
            this.c = c;
        }
    }
    // Define the structure for a tree node
    static class Node {
        List<Edge> edges;
        public Node() {
            edges = new ArrayList<>();
        }
    }
    // Function to perform DFS
    static int dfs(Node[] nodes, int currentNode, int parent, int[] maxLen) {
        int len = 0;
        for (Edge edge : nodes[currentNode].edges) {
            if (edge.u != parent) {
                int childLen = dfs(nodes, edge.u, currentNode, maxLen);
                // Check if the path from the current node to the child node and back is a palindrome
                if (childLen > 0 && edge.c == nodes[currentNode].edges.get(nodes[currentNode].edges.size() - 1).c) {
                    len = childLen + 1;
                }
            }
        }
        if (len > maxLen[0]) {
            maxLen[0] = len;
        }
        return len;
    }
    // Main function
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            Node[] nodes = new Node[N];
            for (int i = 0; i < N; i++) {
                nodes[i] = new Node();
            }
            for (int i = 0; i < N - 1; i++) {
                int v = scanner.nextInt() - 1;
                int u = scanner.nextInt() - 1;
                int c = scanner.nextInt();
                // Add the edge to the adjacency list
                nodes[v].edges.add(new Edge(v, u, c));
                nodes[u].edges.add(new Edge(u, v, c));
            }
            int[] maxLen = new int[] {0};
            for (int i = 0; i < N; i++) {
                dfs(nodes, i, -1, maxLen);
            }
            System.out.println(maxLen[0]);
        }
    }
}

